My solution



src/vga.rs

const ROWS: usize = 80;
const COLS: usize = 25;
const MAX: usize = ROWS * COLS;

fn scroll() {
    unsafe {
        for i in 80..MAX {
            let src: *mut u8 = (MMIO + i * 2) as *mut u8;
            let dst: *mut u8 = (MMIO + (i - 80) * 2)) as *mut u8;
            *dst = *src;
            *((dst as usize + 1) as *mut u8) = COLOR;
        }
        for i in (MAX-80)..MAX {
            let dst: *mut u8 = (MMIO + i * 2) as *mut u8;
            *dst = 32;
            *((dst as usize + 1) as *mut u8) = COLOR;
        }
        LATEST = LATEST - 80;
    }
}

pub fn str_to_vga(s: &str) {
    let v = s.as_bytes();
    unsafe {
        for i in 0..v.len() {
            if LATEST &gt; MAX {
                scroll();
            }
            match v[i] {
                10 =&gt; LATEST = ((LATEST / 80) + 1) * 80,
                _ =&gt; char_to_vga(v[i]),
            }
        }
    }
}

